import { useState } from "react";
import "./index.css";

const initialTasks = [
  { id: 1, name: "Оновити ядро Arch Linux", completed: true },
  { id: 2, name: "Налаштувати кольори Waybar", completed: false },
  { id: 3, name: "Зробити бекап дотфайлів", completed: false },
];

export default function TaskManager() {
  const [tasks, setTasks] = useState(initialTasks);

  function toggleTask(clickedId) {
    const newArray = tasks.map((task) => {
      if (task.id === clickedId) {
        return { ...task, completed: !task.completed };
      } else return task;
    });

    setTasks(newArray);
  }

  return (
    <div className="app-container">
      <h1>Менеджер завдань</h1>
      <div className="task-list">
        {tasks.map((task) => (
          <div
            key={task.id}
            className={`task ${task.completed ? "done" : "pending"}`}
            onClick={toggleTask(() => task.id)}
          >
            <p>{task.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
